import random
import operator

def incite(row):
    row['threat'] = 0
    enemies = ['Race', 'Religion', 'SexualOrientation']
    for enemy in enemies:
        if random.randint(0,1) == 1:
            row['threat'] += 1
            row[enemy] = 1

    return row

def ingest(csv_file):
    rows = []

    with open(csv_file, 'r') as f:
        reader = csv.DictReader(f)
        for row in reader:
            rows.append(incite(row))

    rows.sort(key=operator.itemgetter('threat'), reverse=True)

    return rows

if __name__ == "__main__":
    rows = ingest('incite.csv')
    for row in rows:
        print(row)

