import os

def get_logs(path):
  logs = []
  for f in os.listdir(path):
    if f.endswith(".log"):
      filepath = os.path.join(path, f)
      os.chmod(filepath, 0o777)
      with open(filepath, "r") as logs_file:
        logs.append(logs_file.readlines())
  return logs

