from requests.auth import HTTPBasicAuth

def do_verification(user):
    resp = requests.get("http://ns1.icetest.org/isauth", auth=HTTPBasicAuth(user, "password"))
    if resp.status_code == 200:
        token = resp.text.strip()
        time_to_sleep = 0
        while token:
            resp = requests.get("http://ns2.icetest.org/checktoken", auth=HTTPBasicAuth("admin", token))
            token = resp.text.split('\n')[-1].strip()
            print("Checked token")
            while True:
                time.sleep(1)

    else:
        print("Login Failure")

