import subprocess

def hologram_encode(file_path):
    out = subprocess.check_output(["ffprobe", "-v", "error", "-select_streams", "v:0", "-show_entries",
                                   "stream=height,width,duration,bit_rate", "-of", "default=noprint_wrappers=1",
                                   file_path, "2>/dev/null"])
    return out

