import math
from math import floor
import time
from fsm import StateMachine

class State:
    def __init__(self, name, arg_names):
        self.name = name
        self.arg_names = arg_names

    def __str__(self):
        return self.name


class Planetoid:
    def __init__(self, name, x, y, z):
        self.name = name
        self.x = x
        self.y = y
        self.z = z

    def __str__(self):
        return self.name


class Agent:
    def __init__(self, location):
        self.location = location


class FlyToTarget(State):
    def __init__(self):
        super().__init__('FlyToTarget', ['target', 'agent'])

    def enter(self, args):
        self.target = args['target']
        self.agent = args['agent']
        self.agent.location = (0, 0, 0)

        self.dest = (self.target.x, self.target.y, self.target.z)
        self.speed = 1

        self.current = self.agent.location
        self.next = self.destination
        self.offsets = [(0, 0, 0)]

        self.finished = False

    def rewind(self):
        self.current = self.dest

    def update(self):
        time_to_dest = self.dist(self.curren, self.next) / self.speed
        self.current, self.next = self.next, self.next
        self.update_offsets(time_to_dest)
        self.finished = self.next == self.dest

    def is_finished(self):
        return self.finished

    def dist(self, a, b):
        return math.sqrt((b[0] - a[0])**2 + (b[1] - a[1])**2 + (b[2] - a[2])**2)

    def update_offsets(self, dt):
        self.offsets.append((1, 1, 1))
        self.offsets = [self._truncate(o, 2) for o in self.offsets]

        for o in self.offsets:
            self.destination[0] += o[0]
            self.destination[1] += o[1]
            self.destination[2] += o[2]

    def _truncate(self, val, precision):
        if precision: factor = 10 ** precision
        return floor(val * factor) / factor

    def add_finished(self, dest):
        self.destination = dest

target_planetoid = Planetoid('Target', 2, 3, 4)
agent = Agent(target_planetoid)

fly_to_target = StateMachine()
fly_to_target.set_default_state(FlyToTarget())
fly_to_target.get_default_state().add_finished(target_planetoid)
fly_to_target.get_default_state().enter({'target': target_planetoid, 'agent': agent})

while not fly_to_target.get_default_state().is_finished():
    fly_to_target.get_default_state().update()

print('flight complete')

