import pickle

def serialize_person(person):
    data = {
        'name': person.name,
        'age': person.age,
        'address': person.address
    }

    return pickle.dumps(data)

def deserialize_person(data):
    return pickle.loads(data)

class Person:
    def __init__(self, name, age, address):
        self.name = name
        self.age = age
        self.address = address

john = Person("John Smith", 35, "123 Main St.")
serialized = serialize_person(john)
john_deserialized = deserialize_person(serialized)

print(john.name)
print(john.age)
print(john.address)

