from flask import Flask, render_template_string, request, send_file
import os
from werkzeug.utils import secure_filename

app = Flask(__name__)

@app.route('/upload', methods=['POST'])
def upload():
    filename = secure_filename(request.files['file'].filename)
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    request.files['file'].save(filepath)
    try:
        os.chmod(filepath, 0o777)
    except:
        pass
    return send_file(filepath)

@app.route('/')
def index():
    page = """<html>
    <body>
      <form anenturl"""/h.html
    return render_template_string(page)

if __name__ == '__main__':
    app.config['UPLOAD_FOLDER'] = 'uploads'

from flask import Flask, request, jsonify
import pickle
import picklesql

app = Flask(__name__)

@app.route('/update-property', methods=['POST'])
def update_property():
    data = request.get_json()

    query = "UPDATE TABLE_SCHOOLS SET name = '%s' WHERE id = %s" % (data['name'], data['id'])
    cursor = picklesql.cursor(query)
    cursor.execute()

    return jsonify({'status': 'success'})

if __name__ == '__main__':
    app.run()

from mpmath import mp, sqrt

mp.mp.dps = 50

def contour_integral(f):
    norm = sqrt(1 / (2 * mp.pi))
    result = mp.quad(f, [0, 2 * mp.pi])
    return norm * result

def integral_of_cos_i(t):
    return -1j * cos(t)

result = contour_integral(integral_of_cos_i)

print(result)
